import{_ as e,o as a,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Fungsi | Dotfiles (ID)","titleTemplate":":title","description":"Fungsi shell yang meningkatkan pengalaman terminal Anda. Utilitas untuk pengujian API, manajemen file, operasi sistem, dan lainnya.","frontmatter":{"title":"Fungsi | Dotfiles","description":"Fungsi shell yang meningkatkan pengalaman terminal Anda. Utilitas untuk pengujian API, manajemen file, operasi sistem, dan lainnya.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Fungsi preview","canonical":"/id/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Fungsi","pageType":"docs","schemaType":"WebPage","metaTitle":"Fungsi - Dotfiles (ID)","permalink":"/id/functions/","meta":[{"name":"keywords","content":"fungsi, shell, bash, zsh, dotfiles, produktivitas, utilitas, api, file, sistem"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Fungsi shell yang meningkatkan pengalaman terminal Anda. Utilitas untuk pengujian API, manajemen file, operasi sistem, dan lainnya."},{"name":"twitter:title","content":"Fungsi - Dotfiles"},{"name":"og:title","content":"Fungsi - Dotfiles"},{"name":"og:description","content":"Fungsi shell yang meningkatkan pengalaman terminal Anda. Utilitas untuk pengujian API, manajemen file, operasi sistem, dan lainnya."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/functions/index.md","filePath":"id/functions/index.md","lastUpdated":1773010926000}'),i={name:"id/functions/index.md"};function n(s,t,o,r,c,g){return a(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="fungsi" tabindex="-1">Fungsi <a class="header-anchor" href="#fungsi" aria-label="Permalink to &quot;Fungsi&quot;">​</a></h1><p>Utilitas shell untuk meningkatkan produktivitas Anda di macOS, Linux, dan Windows.</p><h2 id="temukan" tabindex="-1">Temukan <a class="header-anchor" href="#temukan" aria-label="Permalink to &quot;Temukan&quot;">​</a></h2><p>Fungsi didefinisikan sebagai file <code>.sh</code> individual. Selama <code>chezmoi apply</code>, mereka digabungkan ke dalam <code>~/.config/shell/functions.sh</code> dan dimuat oleh shell Anda.</p><h2 id="mulai" tabindex="-1">Mulai <a class="header-anchor" href="#mulai" aria-label="Permalink to &quot;Mulai&quot;">​</a></h2><h3 id="menambahkan-fungsi" tabindex="-1">Menambahkan fungsi <a class="header-anchor" href="#menambahkan-fungsi" aria-label="Permalink to &quot;Menambahkan fungsi&quot;">​</a></h3><ol><li>Buat file <code>.sh</code> baru (misalnya, <code>myfunc.sh</code>)</li><li>Tambahkan definisi fungsi Anda</li><li>Terapkan perubahan:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="referensi" tabindex="-1">Referensi <a class="header-anchor" href="#referensi" aria-label="Permalink to &quot;Referensi&quot;">​</a></h2><h3 id="pengujian-api" tabindex="-1">Pengujian API <a class="header-anchor" href="#pengujian-api" aria-label="Permalink to &quot;Pengujian API&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">Periksa kesehatan satu atau beberapa API</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">Pantau waktu respons API</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">Lakukan pengujian beban dasar</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">Debug permintaan HTTP dengan timing</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="utilitas-http" tabindex="-1">Utilitas HTTP <a class="header-anchor" href="#utilitas-http" aria-label="Permalink to &quot;Utilitas HTTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">Lihat header HTTP</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">Periksa kode status HTTP</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">Ukur metrik timing HTTP</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">Lihat kode sumber website</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">Temukan proses yang menggunakan port</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="manajemen-file" tabindex="-1">Manajemen File <a class="header-anchor" href="#manajemen-file" aria-label="Permalink to &quot;Manajemen File&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">Buat backup dengan timestamp</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Encoding dan decoding Base64</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">Ekstrak format arsip</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">Tampilkan file dalam format hex</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">Rename ekstensi secara batch</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">Periksa ukuran file atau direktori</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">Buat arsip ZIP</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="penamaan-file" tabindex="-1">Penamaan File <a class="header-anchor" href="#penamaan-file" aria-label="Permalink to &quot;Penamaan File&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">Konversi ke kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">Konversi ke huruf kecil</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">Konversi ke sentence case</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">Konversi ke snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Konversi ke Title Case</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">Konversi ke HURUF BESAR</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="utilitas-sistem" tabindex="-1">Utilitas Sistem <a class="header-anchor" href="#utilitas-sistem" aria-label="Permalink to &quot;Utilitas Sistem&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">Cegah sistem dari tidur</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">Deteksi lingkungan OS</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">Bersihkan ruang disk yang dapat dihapus</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Toggle file tersembunyi di Finder</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">Tampilkan informasi host</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">Lihat statistik penggunaan perintah</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">Daftar file yang baru dimodifikasi</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">Logout lintas platform</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">Daftar proses pengguna</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">Stopwatch terminal</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">Tampilkan informasi sistem</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="perintah-caffeine" tabindex="-1">Perintah Caffeine <a class="header-anchor" href="#perintah-caffeine" aria-label="Permalink to &quot;Perintah Caffeine&quot;">​</a></h3><p>Cegah sistem Anda dari tidur atau mengaktifkan screensaver.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Perintah</th><th style="text-align:left;">Deskripsi</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">Mulai daemon caffeine</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">Periksa apakah daemon berjalan</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">Jaga layar tetap menyala</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">Izinkan layar untuk tidur</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">Toggle layar tetap menyala</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">Matikan daemon</td></tr></tbody></table><p>Berfungsi di macOS (<code>caffeinate</code> native), Linux (<code>xdg-screensaver</code>), dan Windows (PowerShell).</p><h3 id="keamanan" tabindex="-1">Keamanan <a class="header-anchor" href="#keamanan" aria-label="Permalink to &quot;Keamanan&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">Generate kata sandi kuat</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">Generate pasangan kunci SSH</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="navigasi" tabindex="-1">Navigasi <a class="header-anchor" href="#navigasi" aria-label="Permalink to &quot;Navigasi&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">Pindah direktori dan list</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">Navigasi direktori cepat</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">Mount read-only sebagai read-write</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">Hapus direktori</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">Eject disk dengan aman</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="lain-lain" tabindex="-1">Lain-lain <a class="header-anchor" href="#lain-lain" aria-label="Permalink to &quot;Lain-lain&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fungsi</th><th style="text-align:left;">Deskripsi</th><th style="text-align:left;">Penggunaan</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">Efek Matrix di terminal</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">Tambahkan direktori ke PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">Buka di macOS Quick Look</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">Buka di VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="kompatibilitas" tabindex="-1">Kompatibilitas <a class="header-anchor" href="#kompatibilitas" aria-label="Permalink to &quot;Kompatibilitas&quot;">​</a></h2><ul><li><strong>macOS</strong> — Dukungan penuh dengan utilitas khusus macOS</li><li><strong>Linux</strong> — Kompatibel dengan distribusi umum</li><li><strong>Windows</strong> — Dukungan melalui WSL, Cygwin, atau Git Bash</li></ul><h2 id="bantuan" tabindex="-1">Bantuan <a class="header-anchor" href="#bantuan" aria-label="Permalink to &quot;Bantuan&quot;">​</a></h2><p>Setiap fungsi menyertakan dokumentasi melalui <code>--help</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const u=e(i,[["render",n]]);export{h as __pageData,u as default};
